cd /home/user/rork-app && bun -e '
const { io } = require("socket.io-client");
const BASE = "https://ivx-holdings-platform.onrender.com";
const room = "audit-cross-" + Date.now();
const socket = io(BASE, { transports: ["websocket"], timeout: 15000 });
const events = [];
const done = (code) => { socket.disconnect(); process.exit(code); };
setTimeout(() => { console.log("TIMEOUT. events:", JSON.stringify(events)); done(1); }, 40000);
socket.on("connect", () => { events.push("connect"); socket.emit("room:join", { roomId: room, userName: "AuditProbe" }); });
socket.on("chat:welcome", (d) => events.push("chat:welcome"));
socket.on("room:joined", (d) => {
  events.push("room:joined");
  socket.emit("chat:send", { roomId: room, text: "cross-store audit probe " + room, userName: "AuditProbe" }, (ack) => {
    events.push("ack:" + JSON.stringify(ack?.ok));
  });
});
socket.on("room:state", () => events.push("room:state"));
let msgCount = 0;
socket.on("chat:message", async (m) => {
  msgCount++;
  events.push("chat:message[" + (m?.role ?? m?.sender ?? "?") + "]");
  if (msgCount >= 2) {
    await new Promise(r => setTimeout(r, 1500));
    const res = await fetch(BASE + "/api/public/messages?roomId=" + room);
    const body = await res.json();
    const msgs = Array.isArray(body) ? body : (body.messages ?? []);
    console.log("REALTIME EVENTS:", JSON.stringify(events));
    console.log("REST HTTP:", res.status, "| REST message count:", msgs.length);
    for (const mm of msgs) console.log("  REST msg:", (mm.role ?? mm.sender ?? "?"), "|", String(mm.text ?? mm.content ?? "").slice(0, 80));
    console.log(msgs.length >= 2 ? "CROSS-STORE: PASS" : "CROSS-STORE: FAIL");
    done(msgs.length >= 2 ? 0 : 1);
  }
});
socket.on("connect_error", (e) => { console.log("connect_error:", e.message); });
' 2>&1

